import streamlit as st


st.title("Streamlit Media Element Example")
st.divider()

st.image("data:image/jpeg;base64,")

images = st.file_uploader("Upload an image", type=["jpg", "jpeg", "png"],accept_multiple_files=True)

print(type(images))

if images :
  col=st.columns(len(images))

  for i, per_image in enumerate(images):
   with col[i]:
    st.image(per_image)